---- MODULE Barrier ----
EXTENDS Integers, Sequences, FiniteSets

VARIABLES n, arrived, released

Init == /\ n = 0
       /\ arrived = {}
       /\ released = {}

Next == \/ /\ n > 0
           /\ arrived' = arrived \cup {n}
           /\ released' = released
           /\ n' = n
       \/ /\ n = 0
           /\ arrived' = {}
           /\ released' = {}
           /\ n' = Len(arrived)

Spec == Init /\ [][Next]_<<n, arrived, released>>

====
